-- ============================================================
--  Alwa Sales — 1 month of sample data
--  Run once in Supabase SQL Editor. Targets YOUR shop (by email).
--  Change the email on the marked line if needed.
-- ============================================================
do $$
declare
  v_shop uuid;
  p1 uuid := gen_random_uuid();
  p2 uuid := gen_random_uuid();
  p3 uuid := gen_random_uuid();
  p4 uuid := gen_random_uuid();
  p5 uuid := gen_random_uuid();
  p6 uuid := gen_random_uuid();
  p7 uuid := gen_random_uuid();
  p8 uuid := gen_random_uuid();
  p9 uuid := gen_random_uuid();
  c1 uuid := gen_random_uuid();
  c2 uuid := gen_random_uuid();
  c3 uuid := gen_random_uuid();
  c4 uuid := gen_random_uuid();
begin
  select shop_id into v_shop from public.profiles pr
    join auth.users u on u.id = pr.id
    where u.email = 'alwak@alphavima.com' limit 1;   -- <-- your login email
  if v_shop is null then raise exception 'No shop found for that email'; end if;

  -- OPTIONAL: start clean — uncomment these 4 lines to wipe this shop's existing
  -- products/customers/invoices/purchases before loading the sample month.
  -- delete from public.invoices  where shop_id = v_shop;
  -- delete from public.purchases where shop_id = v_shop;
  -- delete from public.products  where shop_id = v_shop;
  -- delete from public.customers where shop_id = v_shop;

  update public.shops set name='Alwa Sales', address='Main Road, Durg', pin='491001',
    gstin='22ABCDE1234F1Z5', state='Chhattisgarh', phone='0788-222 3344', invoice_prefix='INV-'
    where id=v_shop;





  -- reduce stock by quantities sold above
  update public.products set stock = stock - 15 where id = p1;
  update public.products set stock = stock - 47 where id = p5;
  update public.products set stock = stock - 67 where id = p8;
  update public.products set stock = stock - 144 where id = p6;
  update public.products set stock = stock - 164 where id = p3;
  update public.products set stock = stock - 15 where id = p7;
  update public.products set stock = stock - 18 where id = p2;
  update public.products set stock = stock - 54 where id = p9;
  update public.products set stock = stock - 71 where id = p4;

  update public.shops set next_invoice_no = 39 where id = v_shop;
  raise notice 'Alwa Sales sample data loaded: % invoices', 38;
end $$;
